**3. `script.js` (JavaScript Funksionallığı)**

```javascript
const digitalClock = document.getElementById('digital-clock');
const alarmHourSelect = document.getElementById('alarm-hour');
const alarmMinuteSelect = document.getElementById('alarm-minute');
const setAlarmBtn = document.getElementById('set-alarm-btn');
const clearAlarmBtn = document.getElementById('clear-alarm-btn');
const alarmSound = document.getElementById('alarm-sound');

let alarmTime = null; // Quraşdırılmış zəng vaxtını saxlayır (məsələn, "14:30")
let isAlarmSet = false; // Zəngin quraşdırılıb-quraşdırılmadığını göstərir

// Vahidə sıfır əlavə etmək üçün funksiya (məsələn, 5 -> 05)
function formatTime(unit) {
    return unit < 10 ? '0' + unit : unit;
}

// Rəqəmsal saatı yeniləmək üçün funksiya
function updateTime() {
    const now = new Date();
    const hours = formatTime(now.getHours());
    const minutes = formatTime(now.getMinutes());
    const seconds = formatTime(now.getSeconds());

    digitalClock.textContent = `${hours}:${minutes}:${seconds}`;

    // Əgər zəng quraşdırılıbsa və cari vaxt zəng vaxtına çatdısa
    if (isAlarmSet && alarmTime === `${hours}:${minutes}`) {
        playAlarm();
        // Zəng aktiv olandan sonra hər saniyə təkrar-təkrar səslənməməsi üçün 
        // buraya əlavə məntiq yaza bilərik. Məsələn, bir dəfə səsləndikdən sonra 
        // "isAlarmSet" dəyişənini müvəqqəti olaraq dayandırmaq və ya sadəcə 
        // istifadəçi silənə qədər səslənməsini təmin etmək. 
        // loop attributu səsin təkrarlanmasını təmin edir.
    }
}

// Saat və dəqiqə açılan siyahılarını doldurmaq üçün funksiya
function populateSelects() {
    // Saatlar (00-23)
    for (let i = 0; i <= 23; i++) {
        const option = document.createElement('option');
        option.value = formatTime(i);
        option.textContent = formatTime(i);
        alarmHourSelect.appendChild(option);
    }

    // Dəqiqələr (00-59)
    for (let i = 0; i <= 59; i++) {
        const option = document.createElement('option');
        option.value = formatTime(i);
        option.textContent = formatTime(i);
        alarmMinuteSelect.appendChild(option);
    }
}

// Zəngi quraşdırmaq üçün funksiya
function setAlarm() {
    const selectedHour = alarmHourSelect.value;
    const selectedMinute = alarmMinuteSelect.value;

    if (selectedHour === '' || selectedMinute === '') {
        alert('Zəng vaxtını seçin!');
        return;
    }

    alarmTime = `${selectedHour}:${selectedMinute}`;
    isAlarmSet = true;

    setAlarmBtn.textContent = 'Zəng Quruldu!';
    setAlarmBtn.disabled = true; // Zəng qurulduqdan sonra düyməni deaktiv et
    clearAlarmBtn.style.display = 'inline-block'; // Sil düyməsini göstər

    alarmHourSelect.disabled = true; // Saat seçicini deaktiv et
    alarmMinuteSelect.disabled = true; // Dəqiqə seçicini deaktiv et

    alert(`Zəng ${alarmTime} üçün quruldu.`);
}

// Zəngi silmək üçün funksiya
function clearAlarm() {
    alarmTime = null;
    isAlarmSet = false;
    alarmSound.pause(); // Səsi dayandır
    alarmSound.currentTime = 0; // Səsi başlanğıca qaytar

    setAlarmBtn.textContent = 'Zəngi Quraşdır';
    setAlarmBtn.disabled = false;
    clearAlarmBtn.style.display = 'none';

    alarmHourSelect.disabled = false;
    alarmMinuteSelect.disabled = false;

    // Vizual əks əlaqə üçün əlavə edilmiş sinifi sil (əgər istifadə olunursa)
    document.body.classList.remove('alarm-active');
}

// Zəng səsini çalmaq üçün funksiya
function playAlarm() {
    // Yalnız zəng quraşdırılıbsa və səsləndirilmirisə çal
    if (isAlarmSet && alarmSound.paused) {
        alarmSound.play().catch(e => console.error("Səs çalınarkən xəta baş verdi:", e));
        // İsteğe bağlı: Vizual əks əlaqə əlavə et (məsələn, ekranın yanıb-sönməsi)
        // document.body.classList.add('alarm-active');
    }
}

// Səhifə yükləndikdə başlanğıc parametrlərini qur
document.addEventListener('DOMContentLoaded', () => {
    populateSelects(); // Seçiciləri doldur
    updateTime(); // Səhifə yüklənəndə cari vaxtı göstər
    setInterval(updateTime, 1000); // Hər saniyə vaxtı yenilə

    // Düymələr üçün hadisə dinləyiciləri
    setAlarmBtn.addEventListener('click', setAlarm);
    clearAlarmBtn.addEventListener('click', clearAlarm);

    // Brauzer avtomatik çalmağı bloklaşdırmışsa, səsi dayandır
    alarmSound.pause();
    alarmSound.currentTime = 0;
});
```

